const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

function calculateQuotePremium(items: any[]): number {
  const typeCounts: Record<string, number> = {};
  for (const item of items) {
    typeCounts[item.type] = (typeCounts[item.type] ?? 0) + 1;
  }

  let totalBasePremium = 0;
  for (const [type, count] of Object.entries(typeCounts)) {
    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
      totalBasePremium += BLOCK_PREMIUM;
    } else {
      totalBasePremium += count * (BASE_PREMIUM[type] ?? 0);
    }
  }

  const firstInsurance = totalBasePremium * FIRST_INSURANCE_RATE;
  return Math.ceil(totalBasePremium + firstInsurance + PROCESSING_FEE);
}

